const body = $json.body || $json;

// ── Extract fields from flat payload ──
const customer_name = body.name || body.customer_name;
const email = body.email;
const phone = body.phone || null;
const service = body.service;
const service_id = body.service_id || null;
const vehicle_size = body.vehicle_size || null;
const vehicle_info = body.vehicle_info || null;
const appointment_time = body.appointment_time;
const address = body.address || null;
const notes = body.notes || null;
const addons = body.addons || null;

// Pricing fields
const base_price_cents = body.base_price_cents || 0;
const addons_cents = body.addons_cents || 0;
const tax_cents = body.tax_cents || 0;
const total_cents = body.total_cents || 0;

// ── Validate ──
if (!customer_name || !email || !service || !appointment_time) {
  throw new Error('Missing required fields. Required: name, email, service, appointment_time');
}

// ── Generate confirmation token ──
const token = `${Date.now()}_${Math.random().toString(36).slice(2)}_${Math.random()
  .toString(36)
  .slice(2)}`;

const baseUrl = 'https://n8n.systack.net/webhook';
const confirm_link = `${baseUrl}/cda-booking-confirmed?token=${encodeURIComponent(token)}`;

// ── SQL-safe versions ──
function sqlSafe(value) {
  if (value === null || value === undefined) return null;
  return String(value).replace(/'/g, "''");
}

// ── Output ──
return [
  {
    json: {
      // Original values (for email, etc.)
      customer_name,
      email,
      phone,
      service,
      service_id,
      vehicle_size,
      vehicle_info,
      appointment_time,
      address,
      addons,
      notes,
      base_price_cents,
      addons_cents,
      tax_cents,
      total_cents,
      confirmation_token: token,
      confirm_link,

      // SQL-safe versions (for Postgres INSERT)
      sql_customer_name: sqlSafe(customer_name),
      sql_email: sqlSafe(email),
      sql_phone: sqlSafe(phone),
      sql_service: sqlSafe(service),
      sql_service_id: sqlSafe(service_id),
      sql_vehicle_size: sqlSafe(vehicle_size),
      sql_vehicle_info: sqlSafe(vehicle_info),
      sql_appointment_time: sqlSafe(appointment_time),
      sql_address: sqlSafe(address),
      sql_addons: sqlSafe(addons),
      sql_notes: sqlSafe(notes),
      sql_confirmation_token: sqlSafe(token),
      sql_confirm_link: sqlSafe(confirm_link)
    }
  }
];

const original = $('Prepare Booking + Token').first().json;

// Handle both array and single-object returns
const insertedRaw = $json;
const inserted = Array.isArray(insertedRaw) ? insertedRaw[0] : insertedRaw;

if (!inserted || !inserted.id) {
  throw new Error('Insert did not return a row. Check Postgres node output.');
}

return [
  {
    json: {
      ...original,
      booking_id: inserted.id,
      status: inserted.status,
      confirmed: inserted.confirmed
    }
  }
];
